%:include"bits/stdc++.h"
%:define int long long
using namespace std;
const int v[]={1,3,5,7,9,10,11,14,15,17};
int f[20],n,a[20],dp[100010],ans;
main(void){
    cin>>n;
    for(int i=1;i<=10;i++)cin>>a[i];
    for(int i=1;i<=10;i++)for(int j=i;j<=10;j++)f[j]=max(f[j-i]+a[i],f[j]);
    for(int i=1;i<=10;i++)for(int j=i;j<=n;j++)dp[j]=max(dp[j-i]+f[i]-v[i-1],dp[j]);
    for(int i=1;i<=n;i++)ans=max(ans,dp[i]);
    cout<<ans;
    return false;
}
